// Postiz webhook payload is the full post object.
const raw = $input.first().json;
const body = raw.body || raw;
const integ = body.integration || {};
const providerName = integ.name || 'unknown';
const providerIdentifier = integ.providerIdentifier || 'unknown';
const content = (body.content || '').slice(0, 200);
const releaseURL = body.releaseURL || '';
const publishDate = body.publishDate || '';
const state = body.state || '';
const integrationPicture = integ.picture || '';

const when = publishDate ? new Date(publishDate).toLocaleString('en-GB', { timeZone: 'Europe/Sofia' }) : 'just now';

const lines = [
  '<b>📤 Posted to ' + providerName + '</b> (' + providerIdentifier + ')',
  '',
];
if (releaseURL) lines.push('<a href="' + releaseURL + '">View on Instagram</a>');
if (content) lines.push('', '<i>' + content + '</i>');
lines.push('', 'state=' + state + ' · published ' + when);

return [{ json: {
  text: lines.join('\n'),
  release_url: releaseURL,
  post_id: body.id,
  integration_id: integ.id,
}}];
